20	  const candidates: Cell[] = [];
21	  for (const [x, y] of liveCells) {
22	    for (let dx = -1; dx <= 1; dx++) {
23	      for (let dy = -1; dy <= 1; dy++) {
24	        if (dx === 0 && dy === 0) continue;
25	        const candidate: Cell = [x + dx, y + dy];
26	        if (isLive(candidate, liveCells)) continue;
27	        if (isLive(candidate, candidates)) continue;
28	        candidates.push(candidate);
29	      }
